// Time:  O(nlogn)
// Space: O(1)

class Solution {
public:
    int minPairSum(vector<int>& nums) {
        sort(begin(nums), end(nums));
        int result = 0;
        for (int i = 0; i < size(nums) / 2; ++i) {
            result = max(result, nums[i] + nums[size(nums) - 1 - i]);
        }
        return result;
    }
};

# Time:  O(nlogn)
# Space: O(1)

class Solution(object):
    def minPairSum(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        nums.sort()
        return max(nums[i]+nums[-1-i] for i in xrange(len(nums)//2))
